import React, { useEffect, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:7000/api/prices";
const CATEGORY_API = "http://localhost:7000/api/categories";

export default function PriceList() {
  const [items, setItems] = useState([]);
  const [categories, setCategories] = useState([]);

  const [form, setForm] = useState({
    name: "",
    category: "",
    description: "",
    basePrice: "",
    difference: "",
    validTill: "",
    imageFile: null,
  });

  const [editId, setEditId] = useState(null);

  useEffect(() => {
    fetchItems();
    fetchCategories();
  }, []);

  const fetchItems = async () => {
    try {
      const res = await axios.get(API_URL);
      setItems(res.data);
    } catch (err) {
      console.error("❌ Fetch error:", err.message);
    }
  };

  const fetchCategories = async () => {
    try {
      const res = await axios.get(CATEGORY_API);
      setCategories(res.data);
    } catch (err) {
      console.error("❌ Category fetch error:", err.message);
    }
  };

  const handleChange = (e) => {
    const { name, value, files } = e.target;
    if (name === "file") {
      setForm({ ...form, imageFile: files[0] });
    } else {
      setForm({ ...form, [name]: value });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData();
    formData.append("name", form.name);
    formData.append("category", form.category);
    formData.append("description", form.description);
    formData.append("basePrice", form.basePrice);
    formData.append("difference", form.difference);
    formData.append("validTill", form.validTill);
    if (form.imageFile) formData.append("file", form.imageFile);

    try {
      if (editId) {
        await axios.put(`${API_URL}/${editId}`, formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });
      } else {
        await axios.post(API_URL, formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });
      }

      setForm({
        name: "",
        category: "",
        description: "",
        basePrice: "",
        difference: "",
        validTill: "",
        imageFile: null,
      });
      setEditId(null);
      fetchItems();
    } catch (err) {
      console.error("❌ Upload error:", err.response?.data || err.message);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this item?")) return;
    await axios.delete(`${API_URL}/${id}`);
    fetchItems();
  };

  const handleEdit = (item) => {
    setForm({
      name: item.name,
      category: item.category,
      description: item.description || "",
      basePrice: item.basePrice,
      difference: item.difference,
      validTill: item.validTill?.split("T")[0] || "",
      imageFile: null,
    });
    setEditId(item._id);
  };

  return (
    <div className="p-6">
      <h2 className="text-2xl font-bold mb-4 text-center">💰 Price Manager</h2>

      {/* ===== FORM ===== */}
      <form
        onSubmit={handleSubmit}
        className="bg-gray-100 p-4 rounded mb-6 shadow-md"
      >
        <input
          name="name"
          placeholder="Item Name"
          value={form.name}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
          required
        />

        {/* ✅ Category Dropdown */}
        <select
          name="category"
          value={form.category}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
          required
        >
          <option value="">Select Category</option>
          {categories.map((cat) => (
            <option key={cat._id} value={cat.name}>
              {cat.name}
            </option>
          ))}
        </select>

        <textarea
          name="description"
          placeholder="Description"
          value={form.description}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
          rows="3"
        />

        <input
          type="number"
          name="basePrice"
          placeholder="New Price"
          value={form.basePrice}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
          required
        />
        <input
          type="number"
          name="difference"
          placeholder="Price Difference (+/-)"
          value={form.difference}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />
        <input
          type="date"
          name="validTill"
          value={form.validTill}
          onChange={handleChange}
          className="border p-2 mb-2 w-full"
        />
        <input
          type="file"
          name="file"
          onChange={handleChange}
          className="border p-2 mb-3 w-full"
        />

        <button
          type="submit"
          className="bg-blue-600 text-white px-4 py-2 rounded"
        >
          {editId ? "Update" : "Add"}
        </button>

        {editId && (
          <button
            type="button"
            onClick={() => setEditId(null)}
            className="ml-3 bg-gray-500 text-white px-4 py-2 rounded"
          >
            Cancel
          </button>
        )}
      </form>

      {/* ===== TABLE ===== */}
      <table className="w-full border-collapse border">
        <thead className="bg-gray-200">
          <tr>
            <th className="border p-2">Image</th>
            <th className="border p-2">Name</th>
            <th className="border p-2">Category</th>
            <th className="border p-2">Description</th>
            <th className="border p-2">Old Price</th>
            <th className="border p-2">Difference</th>
            <th className="border p-2">New Price</th>
            <th className="border p-2">Actions</th>
          </tr>
        </thead>
        <tbody>
          {items.map((it) => {
            const oldPriceEntry =
              it.oldPrices && it.oldPrices.length > 1
                ? it.oldPrices[it.oldPrices.length - 1]
                : null;

            const oldPrice = oldPriceEntry ? oldPriceEntry.price : "-";
            const newPrice = it.displayPrice;

            let diff = "-";
            if (oldPrice !== "-" && !isNaN(oldPrice)) {
              diff = (newPrice - oldPrice).toFixed(2);
            }

            return (
              <tr key={it._id}>
                <td className="border p-2">
                  {it.image ? (
                    <img
                      src={`http://localhost:7000${it.image}`}
                      width="60"
                      alt={it.name}
                    />
                  ) : (
                    "—"
                  )}
                </td>
                <td className="border p-2">{it.name}</td>
                <td className="border p-2">{it.category}</td>
                <td className="border p-2 text-gray-600">
                  {it.description || "—"}
                </td>
                <td className="border p-2 text-gray-600">
                  {oldPrice === "-" ? "—" : `₹${oldPrice}`}
                </td>
                <td
                  className={`border p-2 font-semibold ${
                    diff > 0
                      ? "text-green-600"
                      : diff < 0
                      ? "text-red-600"
                      : "text-gray-700"
                  }`}
                >
                  {diff === "-" ? "—" : `${diff > 0 ? "+" : ""}${diff}`}
                </td>
                <td className="border p-2 font-semibold text-blue-700">
                  ₹{newPrice}
                </td>
                <td className="border p-2">
                  <button
                    onClick={() => handleEdit(it)}
                    className="bg-yellow-400 px-3 py-1 rounded mr-2"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(it._id)}
                    className="bg-red-500 px-3 py-1 text-white rounded"
                  >
                    Delete
                  </button>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}
